class MyStack:
    def __init__(self):
        self.queue1 = []
        self.queue2 = []

    def push(self, x: int) -> None:
        self.queue1.append(x)

    def pop(self) -> int:
        if not self.queue2:
            return -1
        return self.queue2.pop()

    def top(self) -> int:
        return self.queue1[-1]

    def empty(self) -> bool:
        return not self.queue1 or not self.queue2
```

